<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">PATIENT OPERATIONS</span><h1>Appointment Management</h1></div></div><form class="admin-search" method="get"><select name="status"><option value="">All statuses</option><?php foreach(['pending','confirmed','completed','cancelled','no_show']as$s):?><option <?=$status===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input type="date" name="date" value="<?=e($date)?>"><button class="btn outline">Filter</button></form><div class="admin-panel"><div class="table-wrap"><table><thead><tr><th>Reference</th><th>Patient</th><th>Doctor</th><th>Schedule</th><th>Status</th><th>Update</th></tr></thead><tbody><?php foreach($appointments as$a):?><tr><td><?=e($a['appointment_number'])?></td><td><b><?=e($a['patient_name'])?></b><small><?=e($a['phone'])?></small></td><td><?=e($a['doctor_name'])?><small><?=e($a['department_name'])?></small></td><td><?=date('d M Y',strtotime($a['appointment_date']))?><small><?=date('h:i A',strtotime($a['appointment_time']))?></small></td><td><span class="status-pill <?=e($a['status'])?>"><?=e(ucfirst($a['status']))?></span></td><td><form class="inline-update" method="post" action="<?=url('admin/appointment-status')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$a['id']?>"><select name="status"><?php foreach(['pending','confirmed','completed','cancelled','no_show']as$s):?><option <?=$a['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input name="note" placeholder="Administrative note"><button class="btn small">Save</button></form></td></tr><?php endforeach;?></tbody></table></div></div></div></section>

